const e=[{id:"j-boot",title:"Kernel Prayer",body:"The room booted before Evaa did. Bugsy says the walls are honest if you ignore the screaming pixels."},{id:"j-glass",title:"Handprint In Glass",body:"Marry speaks from the reflection like a child hiding under a table during a storm."},{id:"j-city",title:"Billboard Eyes",body:"Neon City knows Evaa by silhouette. Every advert stares back with borrowed pupils."},{id:"j-core",title:"Partition Wound",body:"Bugsy split a feeling into a child-shaped process and called it protection."},{id:"j-sanctuary",title:"A Sky That Stays",body:"Forgiveness did not reboot the world. It made the broken sky bearable."}],t=[{id:"i-terminal",title:"Cracked Terminal Key",type:"tool",body:"Unlocks console commands and lets Evaa hear the OS breathe."},{id:"i-glass",title:"Glass Handprint",type:"relic",body:"Warm to the touch. The scan says it is younger than Evaa and older than grief."},{id:"i-ticket",title:"Platform Zero Ticket",type:"key item",body:"A one-way fare to before. The destination keeps changing when Marry looks at it."},{id:"i-artwork",title:"Secret Sanctuary Sketch",type:"artwork",body:"A hidden drawing file recovered from a folder named DO_NOT_OPEN_ME."}],a={eva:"Evaa becomes more stable when she accepts contradiction instead of deleting it.",marry:"Marry responds to trust, patience, and drawings restored with care.",bugsy:"Bugsy hides tenderness behind diagnostics. His sarcasm spikes when he is afraid.",zero:"Zero provides cryptographically signed guidance when Evaa is ready for truth.",admin:"System Administrator represents rigid emotional walls built to block pain."};export{t as i,e as j,a as r};
